insert into question_options(question_id,label,body,is_correct,sort_order) values (160,'b','Generar muchas muestras Monte Carlo de (μ̂, Σ̂), resolver una frontera por muestra y promediar los pesos al mismo nivel de retorno, obteniendo portafolios más diversificados y estables (un &quot;shrinkage implícito&quot; hacia equiponderación)',true,2);
