insert into question_options(question_id,label,body,is_correct,sort_order) values (167,'b','Porque rebalancear obliga a recortar lo que subió y comprar lo que cayó (vender caro/comprar barato), cosechando la dispersión; el buy-and-hold deja derivar los pesos y &quot;olvida&quot; cosecharla',true,2);
