insert into question_options(question_id,label,body,is_correct,sort_order) values (180,'b','Cliente con views de mercado → Black-Litterman; portafolio institucional con muchos activos → HRP; cliente que piensa por objetivos → BPT + MVO por capa; asignación macro tipo All Weather → Risk Parity',true,2);
