insert into question_options(question_id,label,body,is_correct,sort_order) values (386,'b','La asimetría positiva (positive skewness) de los rendimientos: unas pocas acciones generan rendimientos enormes que arrastran al alza al mercado (ponderado por valor), mientras la acción típica se queda atrás',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (386,'c','Que todas las acciones son iguales',false,3);
