insert into question_options(question_id,label,body,is_correct,sort_order) values (388,'b','Porque en una distribución asimétrica a la derecha el promedio (media) es mayor que la mediana: una acción puede perder a lo sumo 100% pero ganar de forma ilimitada, así que las pocas ganadoras extremas elevan la media por encima de lo que logra la acción típica',true,2);
