insert into question_options(question_id,label,body,is_correct,sort_order) values (389,'b','El rendimiento del mercado (ponderado por valor) está impulsado por las pocas ganadoras extremas; &quot;el mercado&quot; no es lo mismo que &quot;la acción típica&quot;, de modo que el agregado gana aunque la mediana pierda frente a los T-bills',true,2);
