insert into question_options(question_id,label,body,is_correct,sort_order) values (390,'a','Conviene concentrar la cartera en pocas acciones',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (390,'b','Las estrategias activas poco diversificadas (concentradas) tienden a quedar por debajo del promedio del mercado con mayor frecuencia, porque es probable que NO contengan las pocas acciones que generan casi toda la riqueza',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (390,'c','La diversificación es irrelevante',false,3);
