insert into question_options(question_id,label,body,is_correct,sort_order) values (391,'a','Demostrando que el stock picking es fácil',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (391,'b','Mostrando que poseer todo el mercado garantiza tener las pocas ganadoras extremas, mientras seleccionar pocas acciones arriesga perdérselas; es respaldo cuantitativo al &quot;compra el pajar&quot; de Bogle',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (391,'c','Recomendando comprar solo la acción más popular',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (391,'d','Sugiriendo abandonar la renta variable',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (392,'a','Debe mantener la concentración porque seguramente será una ganadora',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (392,'b','La probabilidad de que esa única posición esté en el 4% que crea casi toda la riqueza es muy baja, por lo que diversificar es estadísticamente prudente',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (392,'c','Concentrarse en una acción no tiene riesgo',false,3);
