insert into question_options(question_id,label,body,is_correct,sort_order) values (393,'b','Porque, más allá de las comisiones, la probabilidad estructural de no poseer las pocas ganadoras hace que el bajo desempeño relativo sea probable; la diferencia frente a poseer el mercado puede pesar más que el costo de las comisiones',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (393,'c','Porque la gestión activa siempre gana',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (393,'d','Porque los índices están manipulados',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (394,'a','Que la mayoría de las acciones individuales pierde frente a los T-bills',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (394,'b','NO afirma que la renta variable sea mala ni que el premio accionario sea falso: el mercado agregado SÍ superó ampliamente a los T-bills; el punto es sobre la distribución de resultados individuales y la importancia de la diversificación',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (394,'c','Que la riqueza está muy concentrada en pocas acciones',false,3);
