insert into question_options(question_id,label,body,is_correct,sort_order) values (395,'a','Para convencerlo de concentrarse en su &quot;mejor idea&quot;',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (395,'b','Para recomendarle salir de la renta variable',false,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (395,'c','Para fundamentar la diversificación amplia (índices/fondos), moderar la sobreconfianza en el stock picking, abordar posiciones concentradas y explicar por qué &quot;comprar el mercado&quot; captura a las ganadoras que crean la riqueza, sin negar que el mercado en agregado sí premia al inversionista de largo plazo',true,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (395,'d','Para justificar apalancarse en una sola acción',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (396,'a','Los fondos activos superan ampliamente al mercado después de comisiones',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (396,'b','El portafolio agregado (ponderado por activos) de fondos activos de renta variable de EE.UU. se parece al portafolio de mercado en términos brutos, pero los altos costos de la gestión activa se trasladan íntegros como menores rendimientos para el inversionista (alfa neto agregado negativo, ≈ -0.8% anual en 1984–2006)',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (396,'c','La gestión activa no tiene ningún costo',false,3);
