insert into question_options(question_id,label,body,is_correct,sort_order) values (398,'b','Porque con miles de fondos, algunos parecerán hábiles solo por azar; el bootstrap compara la distribución real de los alfas (sus t-estadísticos) contra la que se generaría bajo la hipótesis nula de que el alfa verdadero es cero para todos los fondos, separando suerte de habilidad',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (398,'c','Para evitar usar datos reales',false,3);
