insert into question_options(question_id,label,body,is_correct,sort_order) values (400,'b','Porque el t(α) controla las diferencias de precisión entre fondos (distinta volatilidad y longitud de historial): un alfa alto de un fondo con poca historia o mucho ruido es menos confiable que uno con historial largo y estable',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (400,'c','Porque el t(α) siempre es mayor',false,3);
