insert into question_options(question_id,label,body,is_correct,sort_order) values (401,'b','Muy pocos fondos generan rendimientos ajustados por riesgo suficientes para cubrir sus costos; la distribución de alfas netos luce peor que la suerte (cola izquierda peor que el azar y cola derecha demasiado delgada para atribuirla a habilidad)',true,2);
