insert into question_options(question_id,label,body,is_correct,sort_order) values (402,'b','Hay evidencia de alfa verdadero distinto de cero en las colas extremas: existen gestores inferiores (sin habilidad) y superiores (con habilidad) antes de costos',true,2);
