insert into question_options(question_id,label,body,is_correct,sort_order) values (405,'c','Afirma que la habilidad de gestión es escasa, difícil de identificar ex ante y, neto de costos, usualmente no llega al inversionista —pero NO que sea imposible ni que el mercado no premie al inversionista de largo plazo—; el asesor lo usa para justificar un núcleo de bajo costo (indexado/pasivo) y para ser humilde y selectivo al recomendar gestión activa',true,3);
