insert into question_options(question_id,label,body,is_correct,sort_order) values (439,'b','Para que la estrategia media-varianza (y sus extensiones) supere de forma confiable al 1/N se necesitarían ~3,000 meses (≈250 años) de datos para 25 activos, y ~6,000 meses (≈500 años) para 50 activos: un horizonte impráctico',true,2);
