insert into question_options(question_id,label,body,is_correct,sort_order) values (442,'b','Las estrategias óptimas suelen exigir rebalanceos frecuentes y grandes (alto turnover), cuyos costos de transacción erosionan el rendimiento neto, mientras que el 1/N tiene un turnover bajo y estable',true,2);
