insert into question_options(question_id,label,body,is_correct,sort_order) values (443,'b','La optimización media-varianza es extremadamente sensible a los rendimientos esperados, que son los parámetros más difíciles y ruidosos de estimar; por eso las carteras de mínima varianza (que ignoran las medias y solo usan covarianzas) tienden a comportarse relativamente mejor, aunque tampoco superan de forma confiable al 1/N',true,2);
