insert into question_options(question_id,label,body,is_correct,sort_order) values (444,'b','NO afirma que la optimización sea inútil en teoría ni que la diversificación no importe: afirma que, en la práctica y fuera de muestra, el error de estimación hace del 1/N un benchmark sorprendentemente difícil de batir; la literatura posterior sigue debatiendo y proponiendo mejoras (shrinkage, restricciones, Black-Litterman)',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (444,'c','Que el error de estimación anula las ganancias de la optimización',false,3);
