insert into question_options(question_id,label,body,is_correct,sort_order) values (500,'b','Garantizando que superará a su índice de referencia',false,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (500,'c','Como el componente de renta variable global (la &quot;bolsa&quot; de acciones) de un cliente con horizonte largo y tolerancia al riesgo, aprovechando la diversificación global, el sesgo a factores y la estructura UCITS (eficiente para inversionistas no estadounidenses), sin prometer que batirá a su benchmark —el rendimiento histórico no garantiza resultados futuros— y dimensionándola según el perfil del cliente',true,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (500,'d','Asignándola al 100% del portafolio de cualquier cliente',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (501,'a','Un fondo de renta variable europea de alta volatilidad',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (501,'b','Una cuenta temática (SMA) de renta fija que invierte en bonos denominados en euros, diseñada para que el inversionista mantenga una posición en euros y se proteja de la fluctuación cambiaria, con instrumentos de baja volatilidad, alta calidad crediticia y corto plazo (y mayor eficiencia fiscal)',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (501,'c','Una nota estructurada apalancada sobre el euro',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (501,'d','Una cuenta de liquidez en pesos',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (502,'a','100% acciones europeas',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (502,'b','Principalmente en ETFs de bonos gubernamentales de la Eurozona (de corto plazo, p. ej., 0-1 y 1-3 años) complementados con bonos corporativos europeos con grado de inversión; predomina el sector gubernamental (~75%), con alta calidad crediticia, duración promedio corta (~8 meses) y un rendimiento a vencimiento del orden de ~2.46% en euros',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (502,'c','Bonos de mercados emergentes de alto rendimiento',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (502,'d','Deuda mexicana en pesos',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (503,'a','Para un cliente que busca máximo crecimiento en renta variable',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (503,'b','Para un cliente que desea exposición o diversificación en euros (p. ej., metas o gastos en esa moneda, o cobertura frente al peso), con un perfil conservador de renta fija, entendiendo que el rendimiento es en euros y queda sujeto a la variable del tipo de cambio EUR/MXN, y que —aunque de baja volatilidad— no está exenta de riesgo de tasa y de crédito',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (503,'c','Para un cliente que necesita liquidez inmediata en pesos sin costo',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (503,'d','Para especular con apalancamiento de corto plazo',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (504,'a','Porque el ETF paga un cupón extra en pesos',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (504,'b','Por la paridad de tasas de interés cubierta: al vender los dólares a futuro (forward), la operación captura el diferencial de tasas vía los puntos forward, de modo que el rendimiento final en pesos se aproxima a la tasa libre de riesgo en pesos (CETES), no al rendimiento del bono en dólares',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (504,'c','Porque los bonos del Tesoro rinden más que los CETES',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (504,'d','Porque se asume un alto riesgo de crédito',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (505,'a','Que el forward es siempre igual al spot',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (505,'b','Como las tasas en pesos suelen ser mayores que en dólares, el peso cotiza a &quot;descuento forward&quot; (Forward &gt; Spot); vender los dólares a futuro a ese precio mayor añade el diferencial de tasas al rendimiento en dólares, de modo que el costo de oportunidad del hedge es renunciar a una eventual ganancia por depreciación del peso a cambio de fijar un rendimiento ≈ CETES',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (505,'c','Que el inversionista gana el rendimiento del Tesoro más toda la depreciación del peso',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (505,'d','Que el hedge no tiene relación con las tasas de interés',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (506,'a','Porque se ignoran los rendimientos en dólares',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (506,'b','Porque al sumar el subyacente [r(T,USD) + r_FX] y la cobertura [−r_FX + (r(T,MXN) − r(T,USD))], los términos cambiarios (r_FX) se cancelan y los rendimientos en dólares (r(T,USD)) también se cancelan, dejando aproximadamente la tasa en pesos r(T,MXN)',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (506,'c','Porque el rendimiento en dólares se duplica',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (506,'d','Porque la cobertura elimina todo rendimiento',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (507,'a','La intervención del banco central',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (507,'b','El arbitraje: si el forward se desviara de su nivel de equilibrio, un arbitrajista podría pedir prestado en pesos, convertir a dólares, invertir en el Tesoro y vender los dólares forward al precio distorsionado para obtener una ganancia sin riesgo; esa actividad presiona el forward de vuelta al equilibrio, por lo que las oportunidades de arbitraje puro son muy raras',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (507,'c','Una regulación de la CNBV que fija el forward',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (507,'d','El azar del mercado',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (508,'a','Obtener el rendimiento del Tesoro de EUA más la apreciación del dólar, sin riesgo',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (508,'b','Maximizar el rendimiento asumiendo riesgo cambiario',false,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (508,'c','Importar la calidad crediticia (Tesoro AAA, superior al techo soberano de México) y la diversificación geográfica de activos no correlacionados con la economía mexicana, manteniendo el rendimiento en pesos (≈ CETES) y sin riesgo cambiario; con eficiencia fiscal (la deuda vía ETFs UCITS tributa como renta variable, ~10% sobre ganancias, frente a hasta ~35% como intereses en inversión directa) y el hedge ya incorporado en los ETFs (MXN Hedged Accumulating de BlackRock/JP Morgan). Es ideal para un cliente conservador que busca mejor calidad crediticia que la deuda mexicana y diversificación, en versión de corto plazo (más conservadora) o mediano plazo (algo más de riesgo/rendimiento)',true,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (508,'d','Especular con el tipo de cambio peso-dólar',false,4);
