insert into question_options(question_id,label,body,is_correct,sort_order) values (538,'a','Vender todo cuando el mercado cae',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (538,'b','Restaurar la asignación objetivo del plan (típicamente vendiendo lo que subió de más y comprando lo que quedó por debajo), ya sea por calendario o cuando se exceden bandas de tolerancia',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (538,'c','Perseguir la inversión que más rindió el mes pasado',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (538,'d','Dejar de aportar',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (539,'a','Lo único que importa es maximizar el valor absoluto del portafolio',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (539,'b','No invertimos en abstracto: lo que importa no es la cifra de riqueza en sí, sino lo que esa riqueza nos permite lograr (nuestras metas), por lo que la inversión siempre es, en el fondo, por objetivos',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (539,'c','Las metas del cliente son irrelevantes para construir el portafolio',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (539,'d','El riesgo se mide solo como varianza',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (540,'a','Las personas son siempre aversas al riesgo',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (540,'b','La curva de utilidad no es de una sola forma, sino &quot;ondulada&quot; (cóncava y convexa por tramos): la persona es aversa al riesgo para protegerse de la pobreza (seguro) y afín al riesgo para buscar el enriquecimiento (lotería)',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (540,'c','Las personas son irracionales sin remedio',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (540,'d','Los seguros y las loterías son la misma cosa',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (541,'a','Únicamente el sesgo cognitivo de tratar el dinero como no fungible',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (541,'b','La observación —no irracional— de que las personas dedican su riqueza a distintas metas y, en respuesta, eligen distintas estrategias y niveles de riesgo para cada una (aun tratando el dinero como fungible)',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (541,'c','Que el dinero nunca debe separarse por objetivos',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (541,'d','Que conviene ignorar las metas del cliente',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (542,'a','La varianza o desviación estándar de los rendimientos',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (542,'b','La probabilidad de no alcanzar el rendimiento mínimo (umbral) necesario para cumplir una meta; es decir, el riesgo es la probabilidad de no lograr el objetivo',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (542,'c','La beta frente al mercado',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (542,'d','La duración de los bonos',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (543,'a','Una sola cartera bien diversificada sobre la frontera media-varianza',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (543,'b','Pirámides por capas: una capa base diseñada para evitar la pobreza (instrumentos seguros, tipo &quot;bonos&quot;) y una capa superior para buscar el enriquecimiento (apuestas de alto potencial, tipo &quot;billetes de lotería&quot;)',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (543,'c','Un único bono cupón cero',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (543,'d','Una cartera 100% en una sola acción',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (544,'a','BPT-SA, que integra todo en una sola cuenta mental',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (544,'b','BPT-MA, en la que el inversionista segrega su riqueza en varias cuentas mentales (capas), cada una asociada a una aspiración o meta con su propia tolerancia al riesgo',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (544,'c','Ninguna; las personas optimizan media-varianza',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (544,'d','Ambas son idénticas',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (545,'a','Porque la BPT prohíbe la diversificación',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (545,'b','Porque el inversionista evalúa cada cuenta mental (capa) por separado e ignora las covarianzas entre capas, de modo que la frontera eficiente de la BPT no coincide con la media-varianza y no se cumple la separación en dos fondos del CAPM',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (545,'c','Porque la BPT solo invierte en efectivo',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (545,'d','Porque la MPT también construye pirámides',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (546,'a','Que los inversionistas solo buscan maximizar el rendimiento esperado',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (546,'b','La tensión entre la seguridad (miedo a la pobreza), el potencial (esperanza de enriquecimiento) y el nivel de aspiración (la meta), reconociendo que las personas, ante la incertidumbre, buscan primero evitar el desastre',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (546,'c','Que el riesgo no existe',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (546,'d','Que la diversificación es irrelevante',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (547,'a','La BPT y la MPT son incompatibles',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (547,'b','Dividir la riqueza en cuentas mentales por objetivos no es irracional ni ineficiente: la probabilidad de no alcanzar un umbral es matemáticamente traducible a un parámetro de aversión al riesgo, de modo que cada meta puede optimizarse al estilo media-varianza',true,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (547,'c','Las cuentas mentales siempre destruyen valor',false,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (547,'d','Conviene ignorar las metas y optimizar una sola cartera',false,4);
insert into question_options(question_id,label,body,is_correct,sort_order) values (548,'a','La contradice, pues exige una sola cartera optimizada para todo',false,1);
insert into question_options(question_id,label,body,is_correct,sort_order) values (548,'b','No tiene relación con la práctica de la asesoría',false,2);
insert into question_options(question_id,label,body,is_correct,sort_order) values (548,'c','Los cajones de Invierte con Propósito son la materialización de las cuentas mentales / capas de la BPT: cada cajón es una meta con su propio horizonte, umbral y tolerancia al riesgo; el riesgo se define como la probabilidad de no alcanzar cada objetivo; y la literatura (Brunel; Das-Markowitz-Scheid-Statman) demuestra que organizar la riqueza así es racional y no ineficiente, validando la metodología',true,3);
insert into question_options(question_id,label,body,is_correct,sort_order) values (548,'d','Solo aplica a inversionistas institucionales',false,4);
